import numpy as np
from langchain.globals import set_llm_cache
from langchain_community.cache import RedisSemanticCache
from langchain_openai import OpenAIEmbeddings

# Drop-in: wraps the LLM cache — same principle applies to retrieval cache
embedding_fn = OpenAIEmbeddings(model="text-embedding-3-small")
set_llm_cache(
    RedisSemanticCache(
        redis_url="redis://localhost:6379",
        embedding=embedding_fn,
        score_threshold=0.93,   # cosine similarity gate
    )
)

# Manual semantic cache for retrieval (not just LLM generation)
class SemanticRetrievalCache:
    def __init__(self, embedder, threshold: float = 0.93, ttl: int = 86400):
        self.embedder = embedder
        self.threshold = threshold
        self.ttl = ttl
        self._store: list[dict] = []  # {embedding, passages, ts}

    def _cosine(self, a, b) -> float:
        return float(np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b) + 1e-9))

    def get(self, query: str) -> list[str] | None:
        q_emb = self.embedder.embed_query(query)
        now = time.time()
        for entry in self._store:
            if now - entry["ts"] > self.ttl:
                continue
            if self._cosine(q_emb, entry["embedding"]) >= self.threshold:
                return entry["passages"]
        return None

    def set(self, query: str, passages: list[str]) -> None:
        q_emb = self.embedder.embed_query(query)
        self._store.append({"embedding": q_emb, "passages": passages, "ts": time.time()})

def flush_retrieval_cache(pattern: str = "rag:exact:*") -> int:
    """Flush all retrieval cache entries after index rebuild."""
    keys = redis_client.keys(pattern)
    if keys:
        redis_client.delete(*keys)
    return len(keys)

