from collections import Counter
import statistics

class CacheObserver:
    def __init__(self):
        self._hits: Counter = Counter()
        self._latencies: list[float] = []

    def record(self, result: RetrievalResult) -> None:
        self._hits[result.cache_layer] += 1
        self._latencies.append(result.latency_ms)

    def report(self) -> dict:
        total = sum(self._hits.values())
        if total == 0:
            return {}
        return {
            "total_queries": total,
            "exact_hit_rate": round(self._hits[CacheLayer.EXACT] / total, 3),
            "semantic_hit_rate": round(self._hits[CacheLayer.SEMANTIC] / total, 3),
            "miss_rate": round(self._hits[CacheLayer.MISS] / total, 3),
            "p50_latency_ms": round(statistics.median(self._latencies), 1),
            "p99_latency_ms": round(sorted(self._latencies)[int(len(self._latencies) * 0.99)], 1)
            if len(self._latencies) >= 100 else None,
        }

observer = CacheObserver()

# Wire into retrieve()
def instrumented_retrieve(cache: TwoLayerRAGCache, query: str) -> list[str]:
    result = cache.retrieve(query)
    observer.record(result)
    return result.passages

# Log every N queries
if observer._hits.total() % 1000 == 0:
    print(observer.report())

import itertools
import numpy as np
from sklearn.metrics.pairwise import cosine_similarity

def calibrate_threshold(
    equivalent_pairs: list[tuple[str, str]],
    non_equivalent_pairs: list[tuple[str, str]],
    embedder,
) -> dict:
    """Find threshold that maximizes F1 on a labeled pair set."""
    all_queries = list({q for pair in equivalent_pairs + non_equivalent_pairs for q in pair})
    embs = {q: embedder.embed_query(q) for q in all_queries}

    def score_pairs(pairs, label: int):
        return [
            (cosine_similarity([embs[a]], [embs[b]])[0][0], label)
            for a, b in pairs
        ]

    scores = (
        score_pairs(equivalent_pairs, 1) +
        score_pairs(non_equivalent_pairs, 0)
    )
    scores.sort(key=lambda x: x[0])

    best_f1, best_thresh = 0.0, 0.9
    for thresh in np.arange(0.80, 0.99, 0.01):
        tp = sum(1 for s, l in scores if s >= thresh and l == 1)
        fp = sum(1 for s, l in scores if s >= thresh and l == 0)
        fn = sum(1 for s, l in scores if s < thresh and l == 1)
        p = tp / (tp + fp + 1e-9)
        r = tp / (tp + fn + 1e-9)
        f1 = 2 * p * r / (p + r + 1e-9)
        if f1 > best_f1:
            best_f1, best_thresh = f1, thresh

    return {"best_threshold": round(best_thresh, 2), "f1": round(best_f1, 3)}

def tenant_cache_key(tenant_id: str, query: str) -> str:
    normalized = query.strip().lower()
    q_hash = hashlib.sha256(normalized.encode()).hexdigest()[:16]
    return f"rag:exact:{tenant_id}:{q_hash}"

class TenantAwareCache(TwoLayerRAGCache):
    def retrieve(self, query: str, tenant_id: str = "default") -> RetrievalResult:
        start = time.perf_counter()
        key = tenant_cache_key(tenant_id, query)

        # Exact cache (tenant-scoped)
        raw = redis_client.get(key)
        if raw:
            redis_client.expire(key, EXACT_TTL)
            return RetrievalResult(json.loads(raw), CacheLayer.EXACT,
                                   (time.perf_counter() - start) * 1000)

        # Fall through to semantic + live (also scoped if needed)
        docs = self.retriever.invoke(query)
        passages = [d.page_content for d in docs]
        redis_client.setex(key, EXACT_TTL, json.dumps(passages))
        return RetrievalResult(passages, CacheLayer.MISS,
                               (time.perf_counter() - start) * 1000)
